actionConfiguration.body:
{{
`
Dear Customer,

Please find your invoice details below.

INVOICE DETAILS
Invoice number: ${GetInvoicePrintHeader.data[0].documentNumber}
Date: ${GetInvoicePrintHeader.data[0].documentDate}
Due date: ${GetInvoicePrintHeader.data[0].dueDate || "-"}
Currency: ${GetInvoicePrintHeader.data[0].currencyCode}

SELLER
${GetInvoicePrintHeader.data[0].companyName}
${GetInvoicePrintHeader.data[0].companyAddress}
${GetInvoicePrintHeader.data[0].companyPostalCode} ${GetInvoicePrintHeader.data[0].companyCity}
VAT/OIB: ${GetInvoicePrintHeader.data[0].companyTaxNumber}
Email: ${GetInvoicePrintHeader.data[0].companyEmail || ""}
Phone: ${GetInvoicePrintHeader.data[0].companyPhone || ""}

BUYER
${GetInvoicePrintHeader.data[0].partnerLegalName || GetInvoicePrintHeader.data[0].partnerName}
${GetInvoicePrintHeader.data[0].partnerAddress || ""}
${GetInvoicePrintHeader.data[0].partnerPostalCode || ""} ${GetInvoicePrintHeader.data[0].partnerCity || ""}
VAT/OIB: ${GetInvoicePrintHeader.data[0].partnerTaxNumber || ""}
Email: ${GetInvoicePrintHeader.data[0].partnerEmail || ""}
Phone: ${GetInvoicePrintHeader.data[0].partnerPhone || ""}

ITEMS
${GetInvoicePrintItems.data.map(row =>
`${row.lineNo}. ${row.description}
   Code: ${row.productCode || ""}
   Quantity: ${Number(row.quantity || 0).toFixed(2)} ${row.unitName || ""}
   Unit price: ${Number(row.unitPrice || 0).toFixed(2)}
   Discount: ${Number(row.discountAmount || 0).toFixed(2)}
   VAT: ${Number(row.taxRate || 0).toFixed(2)}%
   Line total: ${Number(row.lineTotal || 0).toFixed(2)}`
).join("\n\n")}

VAT SUMMARY
${GetInvoicePrintTaxSummary.data.map(row =>
`Rate ${Number(row.taxRate || 0).toFixed(2)}%
   Base: ${Number(row.taxableAmount || 0).toFixed(2)}
   VAT: ${Number(row.taxAmount || 0).toFixed(2)}
   Total: ${Number(row.totalAmount || 0).toFixed(2)}`
).join("\n\n")}

TOTALS
Subtotal: ${Number(GetInvoicePrintHeader.data[0].subtotalAmount || 0).toFixed(2)} ${GetInvoicePrintHeader.data[0].currencyCode}
Discount: ${Number(GetInvoicePrintHeader.data[0].discountAmount || 0).toFixed(2)} ${GetInvoicePrintHeader.data[0].currencyCode}
VAT: ${Number(GetInvoicePrintHeader.data[0].taxAmount || 0).toFixed(2)} ${GetInvoicePrintHeader.data[0].currencyCode}
Total: ${Number(GetInvoicePrintHeader.data[0].totalAmount || 0).toFixed(2)} ${GetInvoicePrintHeader.data[0].currencyCode}
Paid: ${Number(GetInvoicePrintHeader.data[0].paidAmount || 0).toFixed(2)} ${GetInvoicePrintHeader.data[0].currencyCode}
Open amount: ${Number(GetInvoicePrintHeader.data[0].openAmount || 0).toFixed(2)} ${GetInvoicePrintHeader.data[0].currencyCode}

PAYMENT
Payment method: ${GetInvoicePrintHeader.data[0].paymentMethod || "-"}
Operator: ${GetInvoicePrintHeader.data[0].cashier || GetInvoicePrintHeader.data[0].createdBy || "-"}

Kind regards,
${GetInvoicePrintHeader.data[0].companyName}
`
}}
